import re
import subprocess
from pathlib import Path

AC_UID = "07b32ad897136b54"
AC_TYPE = "data"

_FILES = ["hooks/INDEX.md", "docs/reference/INDEX.md"]
_FORBIDDEN = [
    "prehook-overnight-worktree-check.sh",
    "pretool-block-production-files.sh",
    "pretool-block-production.sh",
    "pretool-daily-trade-agent-concurrency.py",
    "configuration-summary.md",
    "incidents-2026-03-28.md",
    "incidents-2026-04-04.md",
    "server-infra.md",
]
_MARKER = "<!-- AUTO:index-stats -->"
# A tree entry line: a box-drawing connector followed by the first backtick name.
_TREE_ENTRY = re.compile(r"[├└]── `([^`]+)`")


def _repo_root() -> Path:
    out = subprocess.run(
        ["git", "rev-parse", "--show-toplevel"],
        capture_output=True, text=True, check=True,
    )
    return Path(out.stdout.strip())


def test_AC4():
    """
    GIVEN: hooks/INDEX.md (7 stale entries, no AUTO marker) and docs/reference/INDEX.md (4 stale, no AUTO marker)
    WHEN:  dev inserts AUTO:index-stats markers around each file's existing generated stats+tree block preserving human prose then runs regen_index() on both directories
    THEN:  neither file lists any deleted file (prehook-overnight-worktree-check.sh, pretool-block-production-files.sh, pretool-block-production.sh, pretool-daily-trade-agent-concurrency.py and .bak, configuration-summary.md, incidents-2026-03-28.md, incidents-2026-04-04.md, server-infra.md) and every backtick entry maps to an existing file and no non-generated prose was lost
    """
    # check kind: index_entries_exist_on_disk
    #   files=["hooks/INDEX.md","docs/reference/INDEX.md"]
    #   marker_required="<!-- AUTO:index-stats -->"  prose_preserved=True
    root = _repo_root()
    for rel in _FILES:
        idx = root / rel
        text = idx.read_text()
        assert _MARKER in text, f"{rel} missing AUTO marker"

        for bad in _FORBIDDEN:
            assert bad not in text, f"{rel} still lists deleted file {bad}"

        d = idx.parent
        for line in text.splitlines():
            m = _TREE_ENTRY.search(line)
            if not m:
                continue
            name = m.group(1)
            matches = list(d.rglob(name))
            assert matches, f"{rel} lists {name} which does not exist on disk"
